import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;

class PageEstimatorPredicateCardinalityRegressionTest {

	private static final int DUMMY_VALUE_COUNT = 300;
	private static final int FOLLOWS_TRIPLE_COUNT = 32;

	@Test
	void keepsNonZeroCardinalityForMultiBytePredicateIds() throws Exception {
		File dataDir = Files.createTempDirectory("lmdb-page-estimator-regression").toFile();
		LmdbStoreConfig config = new LmdbStoreConfig().setPageCardinalityEstimator(true);
		SailRepository repository = new SailRepository(new LmdbStore(dataDir, config));
		IRI follows = SimpleValueFactory.getInstance().createIRI("urn:test:predicate:follows");
		try {
			loadData(repository, follows);

			long actualCount = followsCount(repository, follows);
			assertEquals(FOLLOWS_TRIPLE_COUNT, actualCount, "Regression setup should include follows triples");

			double followsCardinality = followsCardinality(repository, follows);
			assertTrue(followsCardinality > 0, "Expected non-zero follows cardinality with page estimator enabled");
		} finally {
			repository.shutDown();
			FileUtils.deleteDirectory(dataDir);
		}
	}

	private static void loadData(SailRepository repository, IRI follows) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < DUMMY_VALUE_COUNT; i++) {
				IRI subject = iri("urn:test:dummy:subject:", i);
				IRI predicate = iri("urn:test:dummy:predicate:", i);
				IRI object = iri("urn:test:dummy:object:", i);
				connection.add(subject, predicate, object);
			}

			for (int i = 0; i < FOLLOWS_TRIPLE_COUNT; i++) {
				IRI source = iri("urn:test:user:", i);
				IRI target = iri("urn:test:user:", (i + 1) % FOLLOWS_TRIPLE_COUNT);
				connection.add(source, follows, target);
			}
			connection.commit();
		}
	}

	private static long followsCount(SailRepository repository, IRI follows) {
		String query = "SELECT * WHERE { ?s <" + follows.stringValue() + "> ?o . }";
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query).evaluate().stream().count();
		}
	}

	private static double followsCardinality(SailRepository repository, IRI follows) throws Exception {
		EvaluationStatistics statistics = extractEvaluationStatistics(repository);
		StatementPattern followsPattern = followsStatementPattern(follows);
		return statistics.getCardinality(followsPattern);
	}

	private static EvaluationStatistics extractEvaluationStatistics(SailRepository repository) throws Exception {
		Object sail = repository.getSail();
		Method getSailStoreMethod = sail.getClass().getDeclaredMethod("getSailStore");
		getSailStoreMethod.setAccessible(true);
		SailStore sailStore = (SailStore) getSailStoreMethod.invoke(sail);
		return sailStore.getEvaluationStatistics();
	}

	private static StatementPattern followsStatementPattern(IRI followsPredicate) {
		String query = "SELECT * WHERE { ?s <" + followsPredicate.stringValue() + "> ?o . }";
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		List<StatementPattern> patterns = StatementPatternCollector.process(parsed.getTupleExpr());
		return patterns.get(0);
	}

	private static IRI iri(String prefix, int index) {
		return SimpleValueFactory.getInstance().createIRI(prefix + index);
	}
}
